import { PreviewCard } from '@tale-ui/react/preview-card';

export function LinkWithPreviewCard() {
  return (
    <PreviewCard.Root>
      <PreviewCard.Trigger className="tale-button tale-button--neutral tale-button--md">Hover to preview</PreviewCard.Trigger>
      <PreviewCard.Popup placement="bottom" offset={8}>
        <PreviewCard.Arrow />
        <PreviewCard.Content aria-label="Preview">
          <div style={{ maxWidth: '280px' }}>
            <h4 style={{ margin: '0 0 var(--space-xs) 0' }}>Preview Title</h4>
            <p style={{ margin: 0, fontSize: 'var(--text-s-font-size)' }}>
              A quick summary of this linked page or resource.
            </p>
          </div>
        </PreviewCard.Content>
      </PreviewCard.Popup>
    </PreviewCard.Root>
  );
}
